d = {"a": 1, "b": 2}
print("a" in d)
print(1 in d)

exercises.solution:
def duplicates(items):
    seen = set()
    result = []
    added = set()
    for x in items:
        if x in seen and x not in added:
            result.append(x)
            added.add(x)
        seen.add(x)
    return result
